//! F_fold* — Orbit-lock gate.
//!
//! Before applying energy minimization, checks whether any pair of states
//! in the weighted operator sum are in a torsion cycle. If they are, the
//! fold is forbidden — those states represent genuinely distinct perspectives
//! and compressing them destroys information.
//!
//! Register: T.13, D.6b, T.FOUND.3 (evolution equation step 4).

use crate::engine::{Delta, Operator, SaiosParams, compute_rcf_hash};

/// Check whether states Δ_a and Δ_b are in a torsion cycle O_ab ≠ ∅.
///
/// A torsion cycle exists when the orbit of Δ_a under repeated application
/// of the mesh operators returns to Δ_b in finite steps.
///
/// Register: D.6b — orbit-lock condition O_ab ≠ ∅ forbids fold.
pub fn orbit_lock_exists(
    delta_a: &Delta,
    delta_b: &Delta,
    operators: &[Operator],
    max_orbit: usize,
) -> bool {
    let rcf_b = compute_rcf_hash(delta_b);
    let rcf_a = compute_rcf_hash(delta_a);

    for op in operators {
        let mut current = delta_a.clone();
        for step in 0..max_orbit {
            current = match op.apply(&current) {
                Ok(c) => c,
                Err(_) => break,
            };
            // Only valid antisymmetric states can form torsion cycles
            if !current.verify_conservation() {
                break; // operator broke conservation — not a valid orbit element
            }
            let rcf_current = compute_rcf_hash(&current);
            if rcf_current == rcf_b {
                return true; // torsion cycle: Δ_a reaches Δ_b
            }
            // If returned to starting RCF: orbit exhausted under this operator
            if step > 0 && rcf_current == rcf_a {
                break;
            }
        }
    }
    false
}

/// Apply F_fold* gate.
///
/// If orbit lock exists between Δ and any operator image: return identity
/// (no fold — information preserved). If no orbit lock: fold permitted.
///
/// Phase 2.1: single-state fold check against own operator images.
/// Full argmin coherence minimization over orbit is Phase 2.2.
///
/// Register: T.13 (amended — orbit-lock evaluated BEFORE energy minimization).
pub fn f_fold_star(
    delta: &Delta,
    operators: &[Operator],
    _params: &SaiosParams,
) -> Delta {
    for op in operators {
        if let Ok(image) = op.apply(delta) {
            if orbit_lock_exists(delta, &image, operators, 10) {
                // Orbit lock: anti-fold veto — return identity
                return delta.clone();
            }
        }
    }
    // No orbit lock found: fold permitted.
    // Phase 2.1: return identity (simplified — full fold is Phase 2.2).
    // The meaningful action here is the VETO, not the fold itself.
    delta.clone()
}

// ─── Tests ─────────────────────────────────────────────────────────────

#[cfg(test)]
mod tests {
    use super::*;
    use crate::engine::{Delta, Operator, SaiosParams, Q};
    use num_bigint::BigInt;
    use num_traits::{Zero, One};

    fn qr(n: i64, d: i64) -> Q {
        Q::new(BigInt::from(n), BigInt::from(d))
    }

    fn shear_op(dim: usize, row: usize, col: usize, s: &Q) -> Operator {
        let mut mat = vec![vec![Q::zero(); dim]; dim];
        let mut inv = vec![vec![Q::zero(); dim]; dim];
        for i in 0..dim { mat[i][i] = Q::one(); inv[i][i] = Q::one(); }
        mat[row][col] = s.clone();
        inv[row][col] = -s.clone();
        Operator { id: 1, matrix: mat, matrix_inv: inv, det_sign_positive: true }
    }

    fn anchor_2x2() -> Delta {
        let mut d = Delta::zero(2, 1);
        d.set_antisym(0, 1, vec![qr(1, 1)]);
        d
    }

    fn anchor_3x3() -> Delta {
        let mut d = Delta::zero(3, 1);
        d.set_antisym(0, 1, vec![qr(1, 1)]);
        d.set_antisym(1, 2, vec![qr(1, 2)]);
        d.set_antisym(0, 2, vec![qr(3, 2)]);
        d
    }

    #[test]
    fn test_shear_no_orbit_lock_2x2() {
        // Shear is unipotent — does not create torsion cycles on anchor
        let anchor = anchor_2x2();
        let op = shear_op(2, 0, 1, &qr(1, 10));
        assert!(!orbit_lock_exists(&anchor, &anchor, &[op], 10),
            "Shear must not create self-orbit-lock on anchor");
    }

    #[test]
    fn test_shear_no_orbit_lock_3x3() {
        let anchor = anchor_3x3();
        let op = shear_op(3, 0, 1, &qr(1, 50));
        assert!(!orbit_lock_exists(&anchor, &anchor, &[op], 10));
    }

    #[test]
    fn test_f_fold_star_identity_for_shear() {
        // F_fold* must return identity (no fold) for shear on anchor
        let anchor = anchor_3x3();
        let ops = vec![
            shear_op(3, 0, 1, &qr(1, 50)),
            shear_op(3, 1, 2, &qr(1, 75)),
            shear_op(3, 0, 2, &qr(1, 100)),
        ];
        let params = SaiosParams::default_register();
        let result = f_fold_star(&anchor, &ops, &params);
        assert_eq!(result, anchor,
            "Shear operators must not trigger orbit lock on anchor");
    }

    #[test]
    fn test_identity_operator_self_orbit_lock() {
        // Identity operator: A·Δ·A⁻¹ = Δ, so RCF(image) == RCF(Δ) on step 1.
        // This IS a torsion cycle (period 1). Fold must be vetoed.
        let anchor = anchor_2x2();
        let mut mat = vec![vec![Q::zero(); 2]; 2];
        for i in 0..2 { mat[i][i] = Q::one(); }
        let id_op = Operator {
            id: 0, matrix: mat.clone(), matrix_inv: mat, det_sign_positive: true,
        };
        assert!(orbit_lock_exists(&anchor, &anchor, &[id_op.clone()], 10),
            "Identity operator creates period-1 torsion cycle");
        let params = SaiosParams::default_register();
        let result = f_fold_star(&anchor, &[id_op], &params);
        assert_eq!(result, anchor, "Identity orbit lock must veto fold");
    }
}
